dashboard.definition:
{
  "title": "Access Terminal",
  "description": "NAKATOMI PLAZA — PHYSICAL ACCESS CONTROL SYSTEM",
  "dataSources": {
    "ds_results": {
      "type": "ds.search",
      "options": {
        "query": "$spl_query$ | fields - _bkt _cd _indextime _raw _serial _si _subsecond _sourcetype host index linecount source sourcetype splunk_server",
        "queryParameters": {
          "earliest": "0",
          "latest": "now"
        }
      },
      "name": "Query Results"
    },
    "ds_floor_summary": {
      "type": "ds.search",
      "options": {
        "query": "index=nakatomi_access | stats count by floor | sort -count",
        "queryParameters": {
          "earliest": "0",
          "latest": "now"
        }
      },
      "name": "Floor Summary"
    },
    "ds_recent_events": {
      "type": "ds.search",
      "options": {
        "query": "index=nakatomi_access | head 15 | table _time badge_id floor room action outcome",
        "queryParameters": {
          "earliest": "0",
          "latest": "now"
        }
      },
      "name": "Recent Access Events"
    }
  },
  "visualizations": {
    "viz_header": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "```\n> NAKATOMI PLAZA — ACCESS CONTROL SYSTEM v4.7\n> INDEX: nakatomi_access\n> SUBSYSTEM: BADGE READERS / DOOR CONTROLLERS / BIOMETRICS\n> ──────────────────────────────────────────────────────────\n> ENTER SPL QUERY BELOW — ALL ACCESS LOGS AVAILABLE\n```",
        "fontColor": "#33ff33",
        "backgroundColor": "#000d00"
      }
    },
    "viz_results": {
      "type": "splunk.table",
      "title": "> QUERY OUTPUT",
      "dataSources": {"primary": "ds_results"},
      "options": {
        "count": 50,
        "backgroundColor": "#000d00"
      }
    },
    "viz_sidebar_header": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "## > SYSTEM STATUS",
        "fontColor": "#d4a843",
        "backgroundColor": "#000d00"
      }
    },
    "viz_floor_summary": {
      "type": "splunk.table",
      "title": "EVENTS BY FLOOR",
      "dataSources": {"primary": "ds_floor_summary"},
      "options": {
        "count": 40,
        "backgroundColor": "#000d00"
      }
    },
    "viz_recent": {
      "type": "splunk.table",
      "title": "RECENT EVENTS",
      "dataSources": {"primary": "ds_recent_events"},
      "options": {
        "count": 15,
        "backgroundColor": "#000d00"
      }
    },
    "viz_fields": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "**AVAILABLE FIELDS:**\n`badge_id` `floor` `room` `action` `outcome` `detail`\n\n**KEY ACTIONS:**\n`swipe` `override` `denied`\n\n**LOOKUPS:**\n`| inputlookup floor_directory.csv`\n`| inputlookup employee_directory.csv`\n\n**EXAMPLE QUERIES:**\n```\nindex=nakatomi_access floor=1\nindex=nakatomi_access action=override\nindex=nakatomi_access | stats count by floor | sort -count\nindex=nakatomi_access floor=30 room=\"Conference*\"\n```",
        "fontColor": "#1a9a1a",
        "backgroundColor": "#000d00"
      }
    }
  },
  "inputs": {
    "input_spl": {
      "type": "input.text",
      "options": {
        "token": "spl_query",
        "defaultValue": "index=nakatomi_access | head 20 | table _time badge_id floor room action outcome detail"
      },
      "title": "> ENTER SPL QUERY"
    }
  },
  "defaults": {
    "tokens": {
      "spl_query": "index=nakatomi_access | head 20 | table _time badge_id floor room action outcome detail"
    }
  },
  "layout": {
    "type": "grid",
    "globalInputs": [],
    "structure": [
      {"item": "viz_header", "type": "block", "position": {"x": 0, "y": 0, "w": 1200, "h": 120}},
      {"item": "input_spl", "type": "block", "position": {"x": 0, "y": 120, "w": 1200, "h": 70}},
      {"item": "viz_results", "type": "block", "position": {"x": 0, "y": 190, "w": 820, "h": 550}},
      {"item": "viz_sidebar_header", "type": "block", "position": {"x": 820, "y": 190, "w": 380, "h": 50}},
      {"item": "viz_floor_summary", "type": "block", "position": {"x": 820, "y": 240, "w": 380, "h": 260}},
      {"item": "viz_recent", "type": "block", "position": {"x": 0, "y": 740, "w": 820, "h": 350}},
      {"item": "viz_fields", "type": "block", "position": {"x": 820, "y": 500, "w": 380, "h": 590}}
    ]
  }
}
